const allItems = $input.all();

const signals = allItems.map(item => ({
  company: item.json.Company || 'Unknown',
  headline: item.json['Signal Detail'] || '',
  summary: item.json['Outreach Angle'] || '',
  url: item.json['Source URL'] || '',
  actionability: item.json.Actionability || 1,
  state: item.json.Location || '',
  mw: item.json.MW || '',
  contact: item.json.Contact || ''
}));

signals.sort((a, b) => b.actionability - a.actionability);

const seen = new Set();
const deduped = signals.filter(s => {
  if (!s.url || seen.has(s.url)) return false;
  seen.add(s.url);
  return true;
});

return [{ json: { signals: deduped } }];

const records = $input.all().map(r => ({
  id: r.json['Queue ID'] || '',
  mw: r.json['Capacity (MW)'] || '',
  type: r.json.Technology || '',
  state: r.json.State || '',
  county: r.json.County || '',
  score: r.json.Score || '',
  developer: r.json.Developer || '',
  status: r.json['Queue Status'] || ''
}));

return [{ json: { queueRecords: records } }];

const claudeResp = $input.first().json;
const signals = $('Build Claude Prompt').first().json.signals;
let queueRecords;
try {
  queueRecords = $('Prep Queue').first().json.queueRecords || [];
} catch (e) {
  queueRecords = [];
}

let editorial = { bottomLine: '', actOn: '', signals: [] };
try {
  const content = claudeResp.content || [];
  const rawText = (content[0] && content[0].text) ? content[0].text : '{}';
  const text = rawText.replace(/```json|```/g, '').trim();
  editorial = JSON.parse(text);
} catch(e) {
  editorial.bottomLine = 'Editorial generation error. Review signals manually.';
  editorial.actOn = 'Manual review required.';
  editorial.signals = signals.map(s => ({ company: s.company, summary: s.headline, read: s.summary, angle: '' }));
}

const now = new Date();
const TZ = 'America/New_York';
const weekday = now.toLocaleDateString('en-US', { weekday: 'long', timeZone: TZ });
const monthDayYear = now.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric', timeZone: TZ });
const dateStr = weekday + ' &middot; ' + monthDayYear;
const issueNum = Math.floor((now - new Date('2025-01-01')) / (1000 * 60 * 60 * 24));

function actionBadge(score) {
  const n = parseInt(score);
  if (n >= 4) return 'background:#C2410C;color:#ffffff';
  if (n === 3) return 'background:#E6EEF2;color:#0E3A53';
  return 'background:#EDF1F5;color:#5A6B7B';
}

let signalBlocks = '';
signals.forEach((sig, i) => {
  const ed = editorial.signals[i] || { summary: sig.headline, read: sig.summary, angle: '' };
  const badge = actionBadge(sig.actionability);
  const stateStr = sig.state ? '&nbsp;&nbsp;' + sig.state.toUpperCase() : '';
  const mwStr = sig.mw ? ' &middot; ' + sig.mw + ' MW' : '';
  const contactBadge = sig.contact ? '&nbsp;<span style="font-family:Arial,Helvetica,sans-serif;font-size:9px;font-weight:bold;padding:3px 8px;border-radius:2px;background:#0E3A53;color:#fff;">' + sig.contact + '</span>' : '';
  signalBlocks += '<tr><td style="padding:22px 0 0;border-top:1px solid #EDF1F5;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;"><tr><td width="34" valign="top" style="font-family:Georgia,serif;font-size:20px;color:#8A99A8;font-weight:bold;padding-right:8px;">' + (i+1) + '</td><td valign="top"><div style="margin-bottom:6px;"><span style="font-family:Arial,Helvetica,sans-serif;font-weight:bold;font-size:15px;color:#0B1B2B;">' + sig.company + '</span><span style="font-family:\'Courier New\',monospace;font-size:10px;color:#5A6B7B;letter-spacing:0.5px;">' + stateStr + mwStr + '</span>&nbsp;<span style="font-family:Arial,Helvetica,sans-serif;font-weight:bold;font-size:9px;letter-spacing:0.5px;padding:3px 8px;border-radius:2px;' + badge + '">&nbsp;ACTIONABILITY ' + sig.actionability + '&nbsp;</span>' + contactBadge + '</div><div style="font-family:Arial,Helvetica,sans-serif;font-size:14px;line-height:1.45;margin-bottom:8px;"><a href="' + sig.url + '" style="color:#0E3A53;text-decoration:underline;">' + (ed.summary || sig.headline) + '</a></div><div style="font-family:Arial,Helvetica,sans-serif;font-size:13px;line-height:1.5;color:#5A6B7B;margin-bottom:10px;"><span style="font-family:\'Courier New\',monospace;font-size:9px;letter-spacing:1px;color:#C2410C;text-transform:uppercase;">Read&nbsp;&nbsp;</span>' + (ed.read || sig.summary) + '</div><table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;"><tr><td style="background:#F7F5F0;border-left:3px solid #0E3A53;padding:12px 16px;font-family:Arial,Helvetica,sans-serif;font-size:13px;line-height:1.5;color:#28384A;"><span style="font-family:\'Courier New\',monospace;font-size:9px;letter-spacing:1px;color:#0E3A53;text-transform:uppercase;font-weight:bold;">The Angle&nbsp;&nbsp;</span>' + (ed.angle || '') + '</td></tr></table></td></tr></table></td></tr>';
});

let queueBlocks = '';
queueRecords.slice(0, 4).forEach(q => {
  if (!q.id) return;
  queueBlocks += '<td width="50%" valign="top" style="padding:0 8px 12px 0;"><div style="font-family:\'Courier New\',monospace;font-size:11px;font-weight:bold;color:#0E3A53;">' + q.id + '</div><div style="font-family:Arial,Helvetica,sans-serif;font-size:11px;color:#5A6B7B;margin-top:3px;">' + (q.mw ? q.mw + ' MW ' : '') + q.type + ' &middot; ' + (q.county ? q.county + ', ' : '') + q.state + ' &middot; Score ' + q.score + '</div><div style="font-family:Arial,Helvetica,sans-serif;font-size:11px;color:#8A99A8;margin-top:2px;">' + q.developer + ' &middot; ' + q.status + '</div></td>';
});

const queueSection = queueRecords.length > 0 ? '<tr><td style="padding:24px 32px 0;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0"><tr><td style="border-bottom:2px solid #DCE3EA;padding-bottom:7px;"><span style="font-family:\'Courier New\',monospace;font-size:10px;color:#C2410C;font-weight:bold;">02&nbsp;&nbsp;</span><span style="font-family:Arial,Helvetica,sans-serif;font-weight:bold;font-size:14px;color:#0B1B2B;">Queue Spotlight</span></td></tr></table><table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="margin-top:14px;"><tr>' + queueBlocks + '</tr></table></td></tr>' : '';

const html = '<!DOCTYPE html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>NexPhase Advisory Daily Brief</title></head><body style="margin:0;padding:0;background:#EEF1F4;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#EEF1F4;"><tr><td align="center" style="padding:24px 12px;"><table role="presentation" width="640" cellpadding="0" cellspacing="0" style="width:640px;max-width:640px;background:#ffffff;border-collapse:collapse;"><tr><td style="padding:28px 32px 14px;border-bottom:2px solid #0B1B2B;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0"><tr><td valign="middle"><span style="font-family:Arial,Helvetica,sans-serif;font-weight:bold;font-size:18px;color:#0B1B2B;">Nex<span style="color:#C2410C;">Phase</span> Advisory</span><br><span style="font-family:\'Courier New\',monospace;font-size:8px;letter-spacing:2px;color:#8A99A8;text-transform:uppercase;">Power Origination &middot; Interconnection &middot; Strategy</span></td><td valign="middle" align="right"><span style="font-family:Arial,Helvetica,sans-serif;font-weight:bold;font-size:10px;letter-spacing:1px;color:#C2410C;text-transform:uppercase;">Daily Market Signals Brief</span><br><span style="font-family:\'Courier New\',monospace;font-size:10px;color:#5A6B7B;">' + dateStr + '</span></td></tr></table></td></tr><tr><td style="padding:26px 32px 6px;"><div style="font-family:\'Courier New\',monospace;font-size:10px;letter-spacing:2px;color:#C2410C;text-transform:uppercase;margin-bottom:10px;">Issue No. ' + issueNum + ' &middot; US Data Center Power</div><div style="font-family:Georgia,\'Times New Roman\',serif;font-size:28px;line-height:1.1;color:#0B1B2B;font-weight:normal;">The morning <em style="color:#0E3A53;">read</em> on power-constrained demand.</div><div style="font-family:Georgia,serif;font-size:15px;line-height:1.45;color:#28384A;margin-top:12px;">' + signals.length + ' developments worth a power developer&rsquo;s attention today, ranked by where an independent originator can actually create value.</div></td></tr><tr><td style="padding:18px 32px 0;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0"><tr><td style="background:#F7F5F0;border-left:3px solid #C2410C;padding:16px 20px;"><div style="font-family:\'Courier New\',monospace;font-size:9px;letter-spacing:2px;color:#C2410C;text-transform:uppercase;margin-bottom:8px;">Bottom Line</div><div style="font-family:Arial,Helvetica,sans-serif;font-size:14px;line-height:1.5;color:#0B1B2B;">' + editorial.bottomLine + '</div></td></tr></table></td></tr><tr><td style="padding:24px 32px 0;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0"><tr><td style="border-bottom:2px solid #DCE3EA;padding-bottom:7px;"><span style="font-family:\'Courier New\',monospace;font-size:10px;color:#C2410C;font-weight:bold;">01&nbsp;&nbsp;</span><span style="font-family:Arial,Helvetica,sans-serif;font-weight:bold;font-size:14px;color:#0B1B2B;">Ranked by actionability</span></td></tr></table></td></tr><tr><td style="padding:0 32px;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;">' + signalBlocks + '</table></td></tr><tr><td style="padding:24px 32px 0;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0"><tr><td style="background:#0E3A53;padding:20px 24px;"><div style="font-family:\'Courier New\',monospace;font-size:9px;letter-spacing:2px;color:#7FB2C9;text-transform:uppercase;margin-bottom:8px;">What I&rsquo;d Act On</div><div style="font-family:Arial,Helvetica,sans-serif;font-size:14px;line-height:1.5;color:#EAF2F6;">' + editorial.actOn + '</div></td></tr></table></td></tr>' + queueSection + '<tr><td style="padding:24px 32px 28px;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0"><tr><td style="border-top:1px solid #DCE3EA;padding-top:10px;font-family:\'Courier New\',monospace;font-size:9px;line-height:1.6;color:#8A99A8;">NexPhase Advisory &middot; Compiled from public sources &middot; Informational use only &middot; Not investment advice</td></tr></table></td></tr></table></td></tr></table></body></html>';

console.log('Build HTML Brief html length:', html.length);
return [{ json: { html, dateStr, signalCount: signals.length } }];

const fs = require('fs');
const path = require('path');
const os = require('os');
const html = $input.first().json.html;
const now = new Date();
const dateFile = now.toISOString().slice(0, 10);
const dir = path.join(os.homedir(), 'nexphase-reports', 'daily');
const filePath = path.join(dir, dateFile + '.html');
const latestPath = path.join(dir, 'latest.html');
try {
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, html, 'utf8');
  fs.writeFileSync(latestPath, html, 'utf8');
  return [{ json: { success: true, filePath } }];
} catch(e) {
  return [{ json: { success: false, error: e.message } }];
}

// Take top N signals for per-company web-search enrichment (capped for runtime/cost).
const LIMIT = 3;
const signals = ($('Prep Signals').first().json.signals) || [];
const out = [];
signals.slice(0, LIMIT).forEach((s, i) => {
  out.push({ json: { idx: i, company: s.company, headline: s.headline } });
});
return out;

// Map web-search enrichment back onto the full signals array (by original index).
const responses = $input.all();
const splitItems = $('Split Signals').all();
const signals = (($('Prep Signals').first().json.signals) || []).map(s => ({ ...s }));
function parseLevel(text){ const t=(text||'').toUpperCase();
  const labels=['NEEDS HELP','SOPHISTICATED','DEVELOPING'];
  let best='UNKNOWN', bestPos=Infinity;
  labels.forEach(l => { const p=t.indexOf(l); if(p>=0 && p<bestPos){ bestPos=p; best=l; } });
  return best; }
for (let i=0;i<responses.length;i++){
  const sp = splitItems[i] ? splitItems[i].json : {};
  const idx = (sp.idx != null) ? sp.idx : -1;
  const content = (responses[i].json && responses[i].json.content) || [];
  const text = content.filter(b => b.type === 'text').map(b => b.text).join(' ').trim();
  if (idx>=0 && signals[idx]){ signals[idx].sophistication = parseLevel(text); signals[idx].enrichment = text.slice(0,400); }
}
signals.forEach(s => { if(!s.sophistication){ s.sophistication='UNKNOWN'; s.enrichment=''; } });
console.log('Enrichment levels:', signals.map(s => s.company + '=' + s.sophistication).join(' | '));
return [{ json: { signals } }];

// Dedup editorial articles by company name — case-insensitive, strips legal suffixes.
// Mirrors the Lead Generator dedup normalization. Sits after "Merge Editorial + Queue",
// before "Build HTML Brief". Non-editorial items (queue) pass through untouched.
const norm = s => String(s || '').toLowerCase()
  .replace(/\b(llc|inc|corp|ltd|lp|llp|pllc|co\.|company|group|holdings|renewables|energy|power|data centers?|digital)\b/g, '')
  .replace(/[^a-z0-9]+/g, ' ').trim();

const out = [];
for (const item of $input.all()) {
  const j = item.json || {};
  if (Array.isArray(j.content)) {
    // Claude editorial response — dedupe its signals array
    let editorial;
    try {
      const raw = (j.content[0] && j.content[0].text) ? j.content[0].text : '{}';
      editorial = JSON.parse(raw.replace(/```json|```/g, '').trim());
    } catch (e) {
      out.push(item);            // unparseable — leave untouched
      continue;
    }
    if (Array.isArray(editorial.signals)) {
      const seen = new Set();
      editorial.signals = editorial.signals.filter(s => {
        const key = norm(s && s.company);
        if (!key) return true;             // keep unkeyable entries
        if (seen.has(key)) return false;   // drop duplicate company
        seen.add(key);
        return true;
      });
      j.content = [{ ...j.content[0], text: JSON.stringify(editorial) }, ...j.content.slice(1)];
    }
    out.push({ json: j });
  } else {
    out.push(item);              // queue / other items pass through
  }
}
return out;

